"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[914],{49164:n=>{n.exports=JSON.parse('{"functions":[{"name":"new","desc":"Returns a new signal instance which can be used to connect functions.\\n\\n```lua\\nlocal LemonSignal = require(path.to.LemonSignal)\\n\\nlocal signal = LemonSignal.new()\\n```","params":[],"returns":[{"desc":"","lua_type":"Signal"}],"function_type":"static","tags":["Constructor"],"source":{"line":244,"path":"src/init.lua"}},{"name":"wrap","desc":"Returns a new signal instance which fires along with the passed RBXScriptSignal, and a connection object\\nwhich can be used to disable the signal.\\n\\n```lua\\nPlayers.PlayerAdded:Connect(function(player)\\n    print(player, \\"joined, from RBXScriptSignal\\")\\nend)\\n\\nlocal playerAdded = LemonSignal.wrap(Players.PlayerAdded)\\nlocal connection = playerAdded:Connect(function(player)\\n    print(player, \\"joined, from LemonSignal\\")\\nend)\\n\\nplayerAdded:Wait()\\n-- Player1 joins after some time passes\\n\\n--\x3e Player1 joined, from RBXScriptSignal\\n--\x3e Player1 joined, from LemonSignal\\n\\nconnection:Disconnect()\\nplayerAdded:Wait()\\n-- Player2 joins after some time passes\\n\\n--\x3e Player2 joined, from RBXScriptSignal\\n\\nconnection:Reconnect() -- Now we get our hands on more API!\\n-- Player3 joins after some time passes\\n\\n--\x3e Player3 joined, from RBXScriptSignal\\n--\x3e Player3 joined, from LemonSignal\\n\\n-- It can also be used to mock Roblox event fires.\\nplayerAdded:Fire(playerAdded, Players:FindFirstChildOfClass(\\"Player\\")) --\x3e Player1 joined, from LemonSignal\\n```","params":[{"name":"signal","desc":"","lua_type":"RBXScriptSignal"}],"returns":[{"desc":"","lua_type":"Signal"}],"function_type":"static","tags":["Constructor"],"source":{"line":291,"path":"src/init.lua"}},{"name":"Connect","desc":"Connects a function to the signal and returns the connection. Passed variadic arguments will always be prepended to fired arguments.\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\nlocal connection1 = signal:Connect(function(str: string)\\n    print(str)\\nend)\\n\\nlocal connection2 = signal:Connect(print, \\"Hello\\")\\n\\nsignal:Fire(\\"world!\\")\\n--\x3e Hello world!\\n--\x3e world!\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"source":{"line":325,"path":"src/init.lua"}},{"name":"Once","desc":"Connects a function to a signal and disconnects if after the first fire. Can be reconnected later.\\n\\n```lua\\nlocal signal = Signal.new()\\n\\nlocal connection = signal:Once(print, \\"Test:\\")\\n\\nsignal:Fire(\\"Hello world!\\") --\x3e Test: Hello world!\\n\\nprint(connection.Connected) --\x3e false\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"source":{"line":363,"path":"src/init.lua"}},{"name":"Fire","desc":"Fires the signal and calls all connected functions with the connection\'s bound arguments and the fired arguments.\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\nlocal connection = signal:Connect(print, \\"Test:\\")\\n\\nsignal:Fire(\\"Hello world!\\") --\x3e Test: Hello world!\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"source":{"line":389,"path":"src/init.lua"}},{"name":"Wait","desc":"Yields the coroutine until the signal is fired and returns the fired arguments.\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\ntask.delay(1, function()\\n    signal:Fire(\\"Hello\\", \\"world!\\")\\nend)\\n\\nlocal str1, str2 = signal:Wait()\\nprint(str1) --\x3e Hello\\nprint(str2) --\x3e world!\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"yields":true,"source":{"line":451,"path":"src/init.lua"}},{"name":"DisconnectAll","desc":"Disconnects all connections currently connected to the signal. They may be reconnected later.\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\nlocal connection1 = signal:Connect(print, \\"First:\\")\\nlocal connection2 = signal:Connect(print, \\"Second:\\")\\n\\nsignal:Fire(\\"Hello world!\\")\\n--\x3e Second: Hello world!\\n--\x3e First: Hello world!\\n\\nsignal:DisconnectAll()\\n\\nsignal:Fire(\\"Goodbye World!\\")\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"source":{"line":492,"path":"src/init.lua"}},{"name":"Destroy","desc":"Similar to DisconnectAll but also disconnects the RBXScriptConnection made using `.warp`.\\nContrary to the method\'s name, the signal remains usable.\\n\\n```lua\\nlocal signal = LemonSignal.new()\\n\\nlocal connection = signal:Connect(print, \\"Hello\\")\\n\\nsignal:Fire(\\"world!\\")\\n--\x3e Hello world!\\n\\nsignal:Destroy()\\n\\nsignal:Fire(\\"Goodbye World!\\")\\n```","params":[],"returns":[],"function_type":"method","tags":["Method"],"source":{"line":521,"path":"src/init.lua"}}],"properties":[{"name":"RBXScriptConnection","desc":"The RBXScriptConnection that gets made when using [.wrap](#wrap).\\nIt gets disconnected and removed when using [:Destroy](#Destroy).\\n\\n```lua\\nlocal bindable = Instance.new(\\"BindableEvent\\")\\n\\nlocal signal = LemonSignal.wrap(bindable.Event)\\n\\nlocal scriptConnection = signal.RBXScriptConnection\\n\\nprint(signal.RBXScriptConnection) --\x3e Connection\\n\\nsignal:Destroy()\\n\\nprint(scriptConnection.Connected) --\x3e false\\nprint(signal.RBXScriptConnection) --\x3e nil\\n```","lua_type":"RBXScriptConnection?","readonly":true,"source":{"line":92,"path":"src/init.lua"}}],"types":[{"name":"Signal","desc":"","fields":[{"name":"RBXScriptConnection:","lua_type":"RBXScriptConnection?,","desc":""},{"name":"Connect:","lua_type":"<U...>(self: Signal<T...>, fn: (...any) -> (), U...) -> Connection<U...>,","desc":""},{"name":"Once:","lua_type":"<U...>(self: Signal<T...>, fn: (...any) -> (), U...) -> Connection<U...>,","desc":""},{"name":"Wait:","lua_type":"(self: Signal<T...>) -> T...,","desc":""},{"name":"Fire:","lua_type":"(self: Signal<T...>, T...) -> (),","desc":""},{"name":"DisconnectAll:","lua_type":"(self: Signal<T...>) -> (),","desc":""},{"name":"Destroy:","lua_type":"(self: Signal<T...>) -> ()","desc":""}],"source":{"line":68,"path":"src/init.lua"}}],"name":"Signal","desc":"","source":{"line":56,"path":"src/init.lua"}}')}}]);